//! Range proof helpers for the presentation protocol.
//!
//! Spec: draft-ietf-privacypass-arc-crypto-01 §5.4.
//!
//! The range proof establishes that the committed `nonce` lies in
//! `[0, presentation_limit)` without revealing it. It is structured as a
//! per-bit Pedersen bit-decomposition proof combined with a linear-combination
//! sum check over caller-computed *bases*.

use elliptic_curve::Field;
use rand_core::{CryptoRng, RngCore};

use crate::error::{Error, Result};
use crate::group::{generator_g, generator_h, scalar_inverse, Element, Scalar};
use crate::schnorr::{ElementVar, LinearRelation, ScalarVar};

/// `ComputeBases(presentation_limit) -> [b_0, b_1, ..., b_{k-1}]`, returned in
/// **descending** order (matches the WG PoC `range_proof.sage:5-26`).
///
/// `k = ceil(log2(presentation_limit))`. For power-of-two limits the bases are
/// exactly `[2^{k-1}, ..., 2, 1]`. For non-powers of two, the first `k-1`
/// bases are the small-end powers of two `1, 2, ..., 2^{k-2}` and the last
/// (largest) base is chosen so that `sum(bases) == presentation_limit - 1`
/// (the maximum permitted nonce). Descending order matters because the
/// greedy bit decomposition in [`make_range_proof_helper`] consumes the
/// largest base first.
pub fn compute_bases(presentation_limit: u64) -> Vec<Scalar> {
    compute_bases_u64(presentation_limit)
        .into_iter()
        .map(Scalar::from)
        .collect()
}

/// Internal: same as [`compute_bases`] but returns the `u64` values so that
/// [`make_range_proof_helper`] can perform integer comparisons during bit
/// decomposition (`remainder >= base`).
fn compute_bases_u64(presentation_limit: u64) -> Vec<u64> {
    if presentation_limit <= 1 {
        return Vec::new();
    }
    let num_bits = (presentation_limit - 1).ilog2() as usize + 1;
    let mut bases: Vec<u64> = Vec::with_capacity(num_bits);
    let mut remainder = presentation_limit;
    for i in 0..num_bits.saturating_sub(1) {
        let base = 1u64 << i;
        remainder -= base;
        bases.push(base);
    }
    // Final (largest) base: `remainder - 1`. After the power-of-two loop,
    // `remainder = presentation_limit - (2^(k-1) - 1)` so this equals
    // `presentation_limit - 2^(k-1)` (for power-of-two limits, `2^(k-1)`).
    bases.push(remainder - 1);
    bases.sort_by(|a, b| b.cmp(a));
    bases
}

/// Fresh per-bit witnesses generated by the prover.
///
/// For each bit `i`:
/// - `b[i]` — the bit value, `0` or `1` (written as a scalar so it can be
///   fed directly into the Schnorr compiler's witness vector).
/// - `s[i]` — blinding for `D[i] = b[i]·G + s[i]·H`. The last entry is
///   chosen strategically so that `Σ bases[i] · D[i] == nonceCommit`.
/// - `s2[i] = (1 − b[i]) · s[i]` — blinding that linearizes the `b[i] ∈ {0,1}`
///   check (see §5.4.1).
#[derive(Clone, Debug)]
pub struct RangeWitness {
    pub b: Vec<Scalar>,
    pub s: Vec<Scalar>,
    pub s2: Vec<Scalar>,
}

impl RangeWitness {
    /// Concatenate into the layout expected by the Schnorr prover:
    /// `[b_0, …, b_{k-1}, s_0, …, s_{k-1}, s2_0, …, s2_{k-1}]`.
    pub fn to_witness_vec(&self) -> Vec<Scalar> {
        let mut out = Vec::with_capacity(self.b.len() + self.s.len() + self.s2.len());
        out.extend_from_slice(&self.b);
        out.extend_from_slice(&self.s);
        out.extend_from_slice(&self.s2);
        out
    }
}

/// Handles to the newly-allocated variables inside the enclosing linear
/// relation. Returned by [`make_range_proof_helper`] so the caller can wire
/// the base equations (which reference the `D` variables) together with the
/// range equations that this helper already appended.
#[derive(Clone, Debug)]
pub struct RangeVars {
    pub d_element_vars: Vec<ElementVar>,
    pub b_scalar_vars: Vec<ScalarVar>,
    pub s_scalar_vars: Vec<ScalarVar>,
    pub s2_scalar_vars: Vec<ScalarVar>,
}

/// `MakeRangeProofHelper` (§5.4.1).
///
/// Appends range equations to `statement` and returns:
/// - the `D[i]` elements (public commitments, to be serialized in the proof),
/// - the witness scalars (to be concatenated into the prover's witness vector),
/// - variable handles so the caller can bind `D[i]` values with
///   `set_elements` before calling `prove`.
///
/// `gen_g_var`, `gen_h_var` are element-variable handles for `generatorG`
/// and `generatorH`, already allocated and bound by the caller.
///
/// `nonce_commit` / `nonce_commit_var` are the caller's value and handle
/// for the `nonceCommit` element from the base proof. They are passed in to
/// support the **k = 1 special case**: when `presentation_limit == 2`,
/// `k = 1` and the sum check `nonceCommit == bases[0] · D[0]` collapses
/// (with `bases[0] = 1`) to `nonceCommit == D[0]`. In that case the WG PoC
/// does **not** allocate a new element variable for `D[0]`; it reuses
/// `nonce_commit_var`, so the Fiat-Shamir transcript sees one fewer element
/// and one fewer index pair per equation. See `range_proof.sage:86-106` in
/// the WG PoC.
#[allow(clippy::too_many_arguments)]
pub fn make_range_proof_helper<R: RngCore + CryptoRng>(
    statement: &mut LinearRelation,
    nonce: u64,
    nonce_blinding: &Scalar,
    presentation_limit: u64,
    gen_g_var: ElementVar,
    gen_h_var: ElementVar,
    nonce_commit: Element,
    nonce_commit_var: ElementVar,
    rng: &mut R,
) -> Result<(Vec<Element>, RangeWitness, RangeVars)> {
    let bases_u64 = compute_bases_u64(presentation_limit);
    let num_bits = bases_u64.len();
    let bases: Vec<Scalar> = bases_u64.iter().copied().map(Scalar::from).collect();
    let g = generator_g();
    let h = generator_h();

    // Greedy bit decomposition: bases are sorted descending, so we consume
    // the largest base first.
    let mut b_int: Vec<u64> = Vec::with_capacity(num_bits);
    let mut remainder = nonce;
    for &base in &bases_u64 {
        let bit: u64 = if remainder >= base { 1 } else { 0 };
        remainder -= bit * base;
        b_int.push(bit);
    }
    let b: Vec<Scalar> = b_int.iter().copied().map(Scalar::from).collect();

    // Blindings `s`, with the last one chosen so that Σ bases[i]·D[i] == nonceCommit.
    //
    //   Σ bases[i]·D[i] = Σ bases[i]·(b[i]·G + s[i]·H)
    //                  = (Σ bases[i]·b[i])·G + (Σ bases[i]·s[i])·H
    //                  = nonce·G + (Σ bases[i]·s[i])·H
    //
    // and nonceCommit = nonce·G + nonceBlinding·H, so we need
    //   Σ bases[i]·s[i] = nonceBlinding, i.e.
    //   s[last] = (nonceBlinding − Σ_{i<last} bases[i]·s[i]) / bases[last].
    let mut s: Vec<Scalar> = Vec::with_capacity(num_bits);
    let mut s2: Vec<Scalar> = Vec::with_capacity(num_bits);
    let mut d: Vec<Element> = Vec::with_capacity(num_bits);
    let mut partial_sum = Scalar::ZERO;
    let one = Scalar::ONE;

    for i in 0..num_bits.saturating_sub(1) {
        let s_i = Scalar::random(&mut *rng);
        partial_sum += bases[i] * s_i;
        let s2_i = (one - b[i]) * s_i;
        let d_i = g * b[i] + h * s_i;
        s.push(s_i);
        s2.push(s2_i);
        d.push(d_i);
    }
    if num_bits > 0 {
        let idx = num_bits - 1;
        let inv_last = scalar_inverse(&bases[idx])?;
        let s_last = inv_last * (*nonce_blinding - partial_sum);
        let s2_last = (one - b[idx]) * s_last;
        let d_last = g * b[idx] + h * s_last;
        s.push(s_last);
        s2.push(s2_last);
        d.push(d_last);
    }

    // Allocate scalar variables (b, s, s2 — 3k fresh vars in that order).
    let b_vars = statement.allocate_scalars(num_bits);
    let s_vars = statement.allocate_scalars(num_bits);
    let s2_vars = statement.allocate_scalars(num_bits);

    // k = 1 special case: when D[0] == nonce_commit the WG PoC reuses the
    // existing nonce_commit element variable instead of allocating a fresh
    // one. The Fiat-Shamir transcript sees one fewer element index and one
    // fewer stored element as a result.
    let d_vars: Vec<ElementVar> = if num_bits == 1 && d[0] == nonce_commit {
        vec![nonce_commit_var]
    } else {
        let v = statement.allocate_elements(num_bits);
        let bindings: Vec<(ElementVar, Element)> = v
            .iter()
            .zip(d.iter())
            .map(|(ev, el)| (*ev, *el))
            .collect();
        statement.set_elements(&bindings)?;
        v
    };

    // Two equations per bit:
    //   D[i] = b[i]·G + s[i]·H      (standard Pedersen bit commitment)
    //   D[i] = b[i]·D[i] + s2[i]·H  (linearizes b[i] ∈ {0,1}: equals D[i]
    //                                iff b[i]·(1 − b[i]) == 0 in exponent)
    for i in 0..num_bits {
        statement.append_equation(d_vars[i], &[(b_vars[i], gen_g_var), (s_vars[i], gen_h_var)])?;
        statement.append_equation(d_vars[i], &[(b_vars[i], d_vars[i]), (s2_vars[i], gen_h_var)])?;
    }

    Ok((
        d,
        RangeWitness { b, s, s2 },
        RangeVars {
            d_element_vars: d_vars,
            b_scalar_vars: b_vars,
            s_scalar_vars: s_vars,
            s2_scalar_vars: s2_vars,
        },
    ))
}

/// `VerifyRangeProofHelper` (§5.4.2).
///
/// Appends the same range equations to `statement` (bound to the `D[i]`
/// values supplied in the wire proof) and returns whether the non-Schnorr
/// "sum check" holds:
///
/// ```text
/// nonceCommit ?= Σ_i bases[i] · D[i]
/// ```
///
/// The Schnorr verification itself is driven by the caller — this helper only
/// (a) wires the statement and (b) performs the linear sum check.
///
/// **k = 1 special case** (mirrors [`make_range_proof_helper`]): when
/// `presentation_limit == 2` and the deserialized `d[0] == nonce_commit`,
/// the verifier reuses `nonce_commit_var` instead of allocating a fresh
/// element variable.
#[allow(clippy::too_many_arguments)]
pub fn verify_range_proof_helper(
    statement: &mut LinearRelation,
    d: &[Element],
    nonce_commit: Element,
    presentation_limit: u64,
    gen_g_var: ElementVar,
    gen_h_var: ElementVar,
    nonce_commit_var: ElementVar,
) -> Result<bool> {
    let bases_u64 = compute_bases_u64(presentation_limit);
    let num_bits = bases_u64.len();
    if d.len() != num_bits {
        return Err(Error::InvalidLength { expected: num_bits, got: d.len() });
    }

    let b_vars = statement.allocate_scalars(num_bits);
    let s_vars = statement.allocate_scalars(num_bits);
    let s2_vars = statement.allocate_scalars(num_bits);

    let d_vars: Vec<ElementVar> = if num_bits == 1 && d[0] == nonce_commit {
        vec![nonce_commit_var]
    } else {
        let v = statement.allocate_elements(num_bits);
        let bindings: Vec<(ElementVar, Element)> = v
            .iter()
            .zip(d.iter())
            .map(|(ev, el)| (*ev, *el))
            .collect();
        statement.set_elements(&bindings)?;
        v
    };

    for i in 0..num_bits {
        statement.append_equation(d_vars[i], &[(b_vars[i], gen_g_var), (s_vars[i], gen_h_var)])?;
        statement.append_equation(d_vars[i], &[(b_vars[i], d_vars[i]), (s2_vars[i], gen_h_var)])?;
    }

    // Sum check: nonce_commit == Σ bases[i] · D[i].
    let mut sum = Element::default();
    for i in 0..num_bits {
        sum += d[i] * Scalar::from(bases_u64[i]);
    }
    Ok(sum == nonce_commit)
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn compute_bases_limit_2() {
        let bases = compute_bases_u64(2);
        assert_eq!(bases, vec![1]);
    }

    #[test]
    fn compute_bases_power_of_two() {
        assert_eq!(compute_bases_u64(8), vec![4, 2, 1]);
        assert_eq!(compute_bases_u64(16), vec![8, 4, 2, 1]);
    }

    #[test]
    fn compute_bases_non_power_of_two() {
        // For limit=10, num_bits = 4; power-of-two loop produces [1,2,4]
        // with remainder = 10 - 1 - 2 - 4 = 3, so last base = 3 - 1 = 2.
        // Unsorted: [1, 2, 4, 2]; sorted descending: [4, 2, 2, 1].
        // Sum = 4 + 2 + 2 + 1 = 9 = 10 - 1. ✓
        let bases = compute_bases_u64(10);
        assert_eq!(bases, vec![4, 2, 2, 1]);
        assert_eq!(bases.iter().sum::<u64>(), 9);
    }

    #[test]
    fn compute_bases_sum_equals_limit_minus_one() {
        for limit in [2u64, 3, 4, 5, 7, 8, 9, 16, 100, 255, 1024] {
            let bases = compute_bases_u64(limit);
            assert_eq!(
                bases.iter().sum::<u64>(),
                limit - 1,
                "limit = {limit}: bases = {bases:?}"
            );
        }
    }
}
